public TimeSeries createCopy(RegularTimePeriod start, RegularTimePeriod end) throws CloneNotSupportedException {

if (start == null || start.compareTo(end) > 0) {

throw new IllegalArgumentException("Null 'start' or 'end' argument or 'start' on or after 'end'");

}

int startIndex = getIndex(start);

if (startIndex < 0) {

startIndex = -(startIndex + 1);

}

int endIndex = getIndex(end);

if (endIndex < 0) {

endIndex = -(endIndex + 1);

}

if (startIndex == endIndex) {

return createCopy(startIndex, endIndex);

}

int count = endIndex - startIndex + 1;

TimeSeries copy = (TimeSeries) super.clone();

copy.data = new java.util.ArrayList();

for (int i = 0; i < count; i++) {

copy.data.add(this.data.get(startIndex + i));

}

return copy;

}
